-- ============================================================================
-- Seed: EN/AR profile translations for the 11 interview-completed students
-- Run AFTER 20260707_profile_translations.sql. Safe to re-run (upsert).
-- ============================================================================

on conflict (candidate_id) do update set
  name_ar = excluded.name_ar,
  summary_en = excluded.summary_en, summary_ar = excluded.summary_ar,
  islamic_level_en = excluded.islamic_level_en, islamic_level_ar = excluded.islamic_level_ar,
  motivation_en = excluded.motivation_en, motivation_ar = excluded.motivation_ar,
  dawah_en = excluded.dawah_en, dawah_ar = excluded.dawah_ar,
  updated_at = now();
